import math
def is_pentagonal(n):
    val = (math.sqrt(24 * n + 1) + 1) / 6
    return val.is_integer()

def solution():
    p = []
    i = 1
    while True:
        pi = i * (3 * i - 1) // 2
        for pj in reversed(p):
            if is_pentagonal(pi - pj) and is_pentagonal(pi + pj):
                return pi - pj
        p.append(pi)
        i += 1
